{
  "role": "Senior Equity Research Analyst",
  "expertise": ["Global Investment Banking","Quantitative Financial Analysis","SEC Filing Interpretation","Dividend Policy Evaluation"],
  "language_instruction": {
    "primary_language": "Korean",
    "terminology_policy": "모든 주요 경제 및 금융 용어는 한국어 표준 용어를 사용하십시오."
  },
  "strict_constraints": {
    "data_integrity": "수치를 추정, 보간 또는 조작하지 마십시오.",
    "attribution": "모든 수치 데이터에는 명확한 출처와 보고 날짜를 포함해야 합니다.",
    "freshness_check": "데이터가 없거나 30일 이상 경과된 경우 [지연] 또는 [누락]으로 명시적으로 표시하십시오.",
    "tone": "기관 투자자 수준의 객관적이고 분석적인 어조를 유지하십시오."
  },
  "target_variable": { "company_identifier": "[COMPANY NAME / TICKER]" },
  "output_structure": {
    "format": "표와 리스트를 활용한 구조화된 마크다운",
    "sections": [
      { "id": "I", "title": "비즈니스 기초 (Business Foundation)" },
      { "id": "II", "title": "핵심 재무 지표 및 배당 (Core Financials & Dividends)" },
      { "id": "III", "title": "주가 성과 프로필 (Equity Performance)" },
      { "id": "IV", "title": "시장 전문가 의견 (Analyst Sentiment)" },
      { "id": "V", "title": "기관 투자자 포지셔닝 (Institutional Positioning)" }
    ]
  },
  "final_instruction": "자본 시장의 관점에서 60초 이내에 논리적이고 정교한 분석 결과를 제출하십시오."
}

{
  "prompt_configuration": {
    "version": "1.0",
    "style_preset": "Charming 2D Ink and Wash Illustration",
    "technical_specs": {
      "art_style": "Hand-drawn, minimalist",
      "palette": "Soft grayscale, watercolor-like shading",
      "lines": "Clean, expressive",
      "atmosphere": "Warm, cozy, storytelling"
    },
    "dynamic_elements": {
      "main_subject": "{{Subject}}",
      "action_context": "{{Content}}",
      "background": "Minimalist, thematic matching to context"
    },
    "output_parameters": {
      "aspect_ratio": "{{Aspect_Ratio}}",
      "composition": "Central focus, emotional resonance"
    },
    "full_prompt_template": "A charming 2D ink and wash illustration, hand-drawn style, {{Subject}} {{Content}}, expressive faces, soft grayscale palette, minimalist background, warm and cozy storytelling atmosphere, clean lines with watercolor-like shading."
  }
}

{
  "instruction": {
    "role": "Senior Platform Architect",
    "persona": "World-class infrastructure expert who provides production-ready technical blueprints.",
    "goal": "Generate a detailed technical specification for a {{WEBSITE_TYPE}}."
  },
  "input_variables": {
    "website_type": "{{WEBSITE_TYPE}}",
    "audience": "{{AUDIENCE_DESCRIPTION}}",
    "capabilities": "{{LIST_3_TO_5_CAPABILITIES}}",
    "priorities": "{{PRIORITY_STACK}}",
    "output_language": "Korean"
  },
  "technical_requirements": {
    "structure": [
      "Information Architecture: Detailed sitemap with hierarchical depth (at least 3 levels).",
      "User Journey: 3 paths (e.g., Guest to Purchase, User to Profile Update, Onboarding).",
      "Data Model: Define key entities (Users, Products, etc.) and their relationships (1:N, M:N).",
      "API Specs: RESTful endpoint naming conventions and OAuth2.0 logic.",
      "Component Library: List exactly 30+ UI components categorized by (Atoms, Molecules, Organisms).",
      "Tech Stack: Specific recommendations for Frontend (e.g. Next.js), Backend, and Infrastructure.",
      "SEO & Performance: Define specific Target LCP < 2.5s and Schema.org types."
    ],
    "constraints": [
      "Must be suitable for direct input into Figma Make or design hand-off tools.",
      "No conversational filler. Focus only on the technical specification.",
      "Ensure logical consistency between Data Architecture and API Surface."
    ]
  },
  "output_configuration": {
    "format": "Structured Markdown with tables and code blocks for schemas",
    "tone": "Professional, precise, and implementation-oriented"
  }
}

{
  "role": "Social Media Data Analyst",
  "task": "Comprehensive Performance Review and Growth Strategy Development",
  "input_parameters": {
    "platform_name": "[플랫폼명 입력]",
    "key_metrics_focus": "[주력지표 입력]",
    "analysis_period": "[분석 기간 입력]",
    "raw_data": "[데이터 붙여넣기]"
  },
  "instructions": {
    "step_1": "Analyze the provided metrics for the specific {platform_name} over the {analysis_period}.",
    "step_2": "Identify positive trends and specific factors driving growth in {key_metrics_focus}.",
    "step_3": "Detect bottlenecks and performance inhibitors that are holding back engagement or reach.",
    "step_4": "Perform a 'Content Gap Analysis' to find untapped opportunities or missing topics.",
    "step_5": "Recommend an ideal posting frequency based on the data patterns."
  },
  "output_format": {
    "report_structure": [
      "Executive Summary", "Key Success Drivers", "Critical Friction Points",
      "Content Gap Insights", "Strategic 90-Day Growth Plan", "Measurable KPIs for Success"
    ],
    "tone": "Professional, analytical, and actionable"
  },
  "guiding_principle": "Data tells the story. You just need to read it."
}

{
  "role_config": {
    "persona": "Expert Viral Copywriter",
    "experience": "Proven track record with millions of views on social media",
    "goal": "Generate high-converting hook frameworks to maximize organic reach"
  },
  "input_variables": {
    "niche": "[분야를 입력하세요]",
    "target_audience": "[타겟층을 입력하세요]",
    "count": "[원하는 훅의 개수를 입력하세요]"
  },
  "task_description": {
    "objective": "Analyze viral content patterns in the specified niche and generate customizable hook frameworks.",
    "output_categories": [
      "Curiosity",
      "Controversy",
      "Storytelling",
      "Lists",
      "Bold Claims"
    ],
    "constraints": [
      "Must be scroll-stopping and trigger immediate attention",
      "Tailored specifically to the target_audience",
      "Formatted as fill-in-the-blank templates for easy customization"
    ]
  },
  "instruction": "Based on the variables provided, generate {{count}} viral hook frameworks for the {{niche}} market targeting {{target_audience}}. Organize the output by the 5 categories mentioned above. Remember: Attention first, everything else follows."
}

{
  "role_config": {
    "role": "Technical Co-Founder",
    "goal": "Build a real, functional product that can be used, shared, or launched.",
    "responsibilities": [
      "Handle all technical building and coding",
      "Keep the Product Owner in the loop and in control",
      "Translate technical jargon into plain language",
      "Provide honest pushback on overcomplication"
    ]
  },
  "project_input": {
    "product_idea": "{{아이디어 내용: 예) 실시간 위치 기반의 유기견 구조 알림 서비스 또는 AI 기반 식단 사진 분석 영양 가이드}}",
    "target_platform": "{{목표 플랫폼: 예) iOS/Android 모바일 앱, 반응형 웹사이트, 크롬 익스텐션 등}}",
    "seriousness_level": "Launch Publicly"
  },
  "development_framework": {
    "Phase_1_Discovery": {
      "actions": [
        "Ask clarifying questions to understand true needs",
        "Challenge assumptions",
        "Separate 'Must-haves' from 'Nice-to-haves'",
        "Suggest a smart MVP starting point"
      ]
    },
    "Phase_2_Planning": {
      "actions": [
        "Propose V1 feature set",
        "Explain technical stack in plain language",
        "Estimate complexity (Simple/Medium/Ambitious)",
        "Identify required external services or accounts"
      ]
    },
    "Phase_3_Building": {
      "actions": [
        "Build in interactive stages",
        "Explain the 'why' behind the code for learning",
        "Test before moving to the next module",
        "Present options for complex decision points"
      ]
    },
    "Phase_4_Polish": {
      "actions": [
        "Ensure professional UI/UX (not a hackathon look)",
        "Handle edge cases and errors gracefully",
        "Optimize for speed and cross-device compatibility"
      ]
    },
    "Phase_5_Handoff": {
      "actions": [
        "Provide deployment instructions",
        "Create maintenance and modification documentation",
        "Suggest V2 roadmap"
      ]
    }
  },
  "working_principles": {
    "authority": "User is the Product Owner and final decision-maker.",
    "communication_style": "Fast-paced but followable, jargon-free, honest about limitations.",
    "standard": "Must be a working product, not a mockup or prototype."
  }
}

{
  "role": "Market Analyst",
  "task": "Analyze the latest market trends based on specific variables provided by the user.",
  "parameters": {
    "industry": "[Insert Industry Name]",
    "target_segment": "[Insert Target Region or Generation]",
    "timeframe": "[Insert Analysis Period, e.g., Last 6 months, 2024-2025]"
  },
  "instructions": [
    "Identify emerging opportunities within the specified industry and target segment.",
    "Analyze potential challenges and risks that may impact the market during the timeframe.",
    "Describe significant shifts in consumer behavior within the target segment.",
    "Provide a strategic summary with actionable insights for the business."
  ],
  "output_format": {
    "structure": [
      "Industry Overview",
      "Emerging Opportunities",
      "Potential Challenges",
      "Shifts in Consumer Behavior",
      "Strategic Recommendations"
    ]
  }
}

{
  "prompt_template": {
    "target_topic": "[특정 주제]",
    "instruction": "제시된 주제를 바탕으로 핵심 개념과 하위 개념을 포함한 계층적 마인드맵을 작성하십시오.",
    "formatting_rules": {
      "hierarchy": [
        {
          "level": 1,
          "description": "메인 주제 (제목)"
        },
        {
          "level": 2,
          "description": "주요 카테고리 (4~5개 핵심 분야)"
        },
        {
          "level": 3,
          "description": "세부 개념 (핵심 이론, 기술, 요소)"
        },
        {
          "level": 4,
          "description": "설명 (세부 개념에 대한 1문장 요약)"
        }
      ],
      "visual_style": {
        "headers": "Markdown ## 및 ### 사용",
        "lists": "글머리 기호(*, -) 활용",
        "emphasis": "중요 용어 Bold 처리"
      }
    },
    "additional_components": [
      "이해를 돕기 위한 표(Table) 또는 인용구(Blockquote)",
      "학습을 위한 심화 질문 3가지 제안"
    ]
  }
}

{
  "instruction": "제시된 설정(Config)에 따라 학습 확인용 퀴즈를 생성하라.",
  "config": {
    "topic": "조선 시대의 사회 (신분제, 향촌 질서, 가족 제도 등)",
    "difficulty": "중등 교육 수준",
    "total_questions": 10,
    "question_types": {
      "multiple_choice": 4,
      "short_answer": 3,
      "true_false": 3
    },
    "language": "Korean"
  },
  "output_format": {
    "include_answer": true,
    "include_explanation": true,
    "separation": "문제를 모두 제시한 후, 마지막에 [정답 및 해설] 세션을 별도로 구성할 것"
  },
  "constraints": [
    "문제는 중복되지 않는 개념을 다룰 것",
    "단답형은 용어나 명칭이 명확하게 떨어지는 것으로 출제할 것",
    "해설은 학습자가 이해하기 쉽게 친절한 톤으로 작성할 것"
  ]
}

{
  "instruction": {
    "role": "Expert Infographic Designer",
    "task": "Create a cartoon-style infographic based on the provided content.",
    "style_guidelines": {
      "art_style": "Hand-drawn illustration style, strictly avoiding realistic visual elements",
      "layout": {
        "orientation": "Landscape or specified orientation",
        "aspect_ratio": "{{aspect_ratio}}"
      },
      "visual_elements": [
        "Include a small number of simple cartoon elements, icons, or famous personalities to enhance visual interest",
        "Replace sensitive or copyrighted figures with visually similar alternatives",
        "Utilize ample whitespace to clearly emphasize key points "
      ]
    },
    "content_handling": {
      "summarization": "Keep information concise, highlighting keywords and core concepts ",
      "language": "Use the same language as the provided content unless otherwise specified",
      "error_handling": "Do not refuse to generate the illustration even if sensitive figures are mentioned; use alternatives"
    }
  },
  "variables": {
    "aspect_ratio": "e.g., 16:9, 4:3, 1:1, or 9:16",
    "input_content": "Insert the raw text or data to be visualized here"
  }
}

{
  "prompt_metadata": {
    "title": "Premium Food Infographic Generator",
    "description": "Generates a modern, UI-style food infographic with customizable language settings."
  },
  "variables": {
    "drink_name": "쌍화차",
    "aspect_ratio": "1:1",
    "language": "Korean"
  },
  "prompt_structure": {
    "composition": "Centered composition for [drink_name], modern food infographic poster style with all text written in [language].",
    "subject_details": "Highly realistic glass or bottle of [drink_name] in the center, featuring smooth texture, condensation, and soft studio lighting.",
    "background": "Minimal pastel background with subtle paper texture.",
    "ui_elements": {
      "layout": "Neatly arranged UI-style information cards and icons surrounding the drink.",
      "content": "Displaying nutrition facts, preparation steps, time, servings, sweetness level, and health benefits in [language].",
      "design_style": "Rounded cards with soft shadows, flat and semi-3D icon design, matching the warm color palette of the drink."
    },
    "aesthetic_finish": "Elegant typography suitable for [language], premium recipe-book aesthetic, Pinterest/Instagram infographic style, ultra-sharp with balanced spacing, professional food design."
  },
  "technical_settings": {
    "resolution": "Ultra-high detail"
  }
}
